var validateDockerComposeFile = function(composeFile) {
  const yamlConfig = YAML.parse(composeFile);
  const services = yamlConfig.services;

  const serviceNameSet = new Set();

  for (const service of services) {
    const ports = service.ports;
    const serviceName = service.name;

    if (serviceNameSet.has(serviceName)) {
      return false;
    }

    serviceNameSet.add(serviceName);
  }

  return true;
};

module.exports = validateDockerComposeFile;

